// Try different arithmetic operations
let a = 20;
let b = 3;

console.log("Addition: " + (a + b));
console.log("Subtraction: " + (a - b));
console.log("Multiplication: " + (a * b));
console.log("Division: " + (a / b));
console.log("Remainder: " + (a % b));

// Try your own calculations!
console.log(5 + 5 * 2);  // What order does this calculate?

// Comparisons always return true or false
console.log(10 > 5);      // true
console.log(10 < 5);      // false
console.log(10 === 10);   // true
console.log(10 === "10"); // false (different types!)

// Try your own comparisons
let x = 15;
let y = 20;

console.log(x < y);
console.log(x === y);

// AND (&&) - both must be true
console.log(true && true);    // true
console.log(true && false);   // false

// OR (||) - at least one must be true
console.log(true || false);   // true
console.log(false || false);  // false

// NOT (!) - reverses the value
console.log(!true);           // false
console.log(!false);          // true

// Real examples
let age = 25;
let hasLicense = true;
console.log(age >= 18 && hasLicense);  // Can drive?
